$_MODULE['<{PrestashopAPI}prestashop>d4eb463703a7e5de947f59c53ef36bfa'] = 'No hay facturas devueltas por el marketplace para este período.';
$_MODULE['<{PrestashopAPI}prestashop>1c1325208aa668df5ebd5590d78559b1'] = 'Añada su clave API para ver sus pagos.';
$_MODULE['<{PrestashopAPI}prestashop>9cf3cea9fc2559bc3932a1034a8c77bd'] = 'Mantener los datos actualizados automáticamente';
$_MODULE['<{PrestashopAPI}prestashop>70fab415490de4d1c4d958b059ff1cbf'] = 'La insignia de la tienda y las cifras anteriores se leen de una copia local de sus datos del marketplace, para que ningún visitante de su tienda espere al marketplace. Esa copia se actualiza al abrir esta página. Para actualizarla según un horario, llame a esta URL desde una tarea cron, por ejemplo una vez por hora:';
$_MODULE['<{PrestashopAPI}prestashop>9b4fe89ace5fbb71472cf7a6c3c0ffe9'] = 'Mantenga esta URL privada: quien la tenga puede activar una actualización. Cambia si reinstala el módulo.';
$_MODULE['<{PrestashopAPI}prestashop>850d45fc61bfd3cd575cbc45addd9529'] = 'Datos en caché';
$_MODULE['<{PrestashopAPI}prestashop>058881da8f789da85e445bfd42bdee3c'] = 'Si algo parece incorrecto, borre la copia local y descargue todo de nuevo.';
$_MODULE['<{PrestashopAPI}prestashop>dc034e19f7696e490bc7229a3f70142c'] = 'Borrar datos en caché';
$_MODULE['<{PrestashopAPI}prestashop>3b488ade6f134eacce53039c0d3b7908'] = 'Cómo funciona este módulo';
$_MODULE['<{PrestashopAPI}prestashop>2b567533f379fab2c398929de7c99c2e'] = 'De dónde vienen las cifras';
$_MODULE['<{PrestashopAPI}prestashop>1438971d29f373379a0ca6b9e82f04b0'] = 'Las cifras del marketplace se descargan de la API Vendedor de PrestaShop Addons con su propia clave API, y se almacenan localmente. Sus cifras de tienda provienen de sus pedidos válidos. Nada se envía a otro lugar.';
$_MODULE['<{PrestashopAPI}prestashop>e9ac528d46587d227713f545b102975e'] = 'Por qué algunos productos no muestran ventas de tienda';
$_MODULE['<{PrestashopAPI}prestashop>3585339aed30ba73e0e738d458cff45e'] = 'El módulo debe saber qué producto de su catálogo es el mismo que cuál en el marketplace. Los vincula cuando la referencia de su producto coincide con el ID de producto del marketplace. Si usa referencias diferentes, fíjelos manualmente en la pestaña Productos.';
$_MODULE['<{PrestashopAPI}prestashop>53beb26d8bca00f56fbd295fdee83459'] = 'Reembolsos';
$_MODULE['<{PrestashopAPI}prestashop>de980f4d92dea658e437fb1a6db084fd'] = 'Las unidades reembolsadas se restan de unidades e ingresos, en ambos lados, para que los totales reflejen lo que realmente conservó.';
$_MODULE['<{PrestashopAPI}prestashop>dfcfc43722eef1eab1e4a12e50a068b1'] = 'Monedas';
$_MODULE['<{PrestashopAPI}prestashop>9bd1ea4499517071a96ee0340edeccf5'] = 'Los pagos del marketplace suelen ser en euros mientras su tienda puede vender en otra moneda. Los totales combinados usan el tipo de cambio de su tienda. Sin tipo para la moneda del marketplace, los totales combinados se ocultan en lugar de estimarse.';
$_MODULE['<{PrestashopAPI}prestashop>9635c7ca9186a5b541c68c3e54afc07d'] = 'La insignia de la tienda';
$_MODULE['<{PrestashopAPI}prestashop>8224e1ccb8232fe6f2ccd4fbeb8c2374'] = 'Opcionalmente, las páginas de producto de su propia tienda pueden mostrar cuántas veces se ha descargado un producto, como prueba social. Proviene de la copia local de sus datos, sin tiempo de carga extra, y se oculta bajo el umbral que establezca.';
$_MODULE['<{PrestashopAPI}prestashop>44877c6aa8e93fa5a91c9361211464fb'] = 'Velocidad';
$_MODULE['<{PrestashopAPI}prestashop>803e2b0d8f5afc76e2e54fad606490c0'] = 'Un período de informe amplio significa más filas que descargar. Si la actualización parece lenta, reduzca el período o alargue el intervalo en Configuración.';
$_MODULE['<{PrestashopAPI}prestashop>8b9c1abd043bde61211bc6d58be58370'] = 'Si algo no funciona';
$_MODULE['<{PrestashopAPI}prestashop>f2cb075d74e523731af10acbb1177695'] = 'Su servidor no pudo abrir una conexión HTTPS saliente al marketplace. El hosting compartido suele bloquearlo. La lista Estado de la pestaña Panel indica si cURL está disponible; si lo está, pregunte a su hosting si se permiten conexiones salientes a api.addons.prestashop.com.';
$_MODULE['<{PrestashopAPI}prestashop>f64dc4589dc99c8b6633332d2cd64673'] = 'Genere una clave nueva en su cuenta de vendedor, en Configuración luego API, y péguela de nuevo. Copie solo la clave, no el texto alrededor.';
$_MODULE['<{PrestashopAPI}prestashop>e42e9d958504c5158fe91c5d56ee6214'] = 'Las cifras son más antiguas de lo que deberían';
$_MODULE['<{PrestashopAPI}prestashop>cce5ffc741270470dec823a4fff75552'] = 'Las ventas de tienda son cero para cada producto';
$_MODULE['<{PrestashopAPI}prestashop>95dab330ce5b2c1d94467c07916fea17'] = 'Ninguno de sus productos del marketplace coincidió con un producto de su catálogo. Revise la lista Estado en la pestaña Panel, y fije los productos manualmente en la pestaña Productos.';
$_MODULE['<{PrestashopAPI}prestashop>e67411c887a32a48389e48e21d409fca'] = 'Qué devuelve la API';
$_MODULE['<{PrestashopAPI}prestashop>9d0b331fa4855d2fc2b8ffca416cc545'] = 'El marketplace solo documenta sus productos y datos de ventas. Todo lo demás, incluidas conversaciones, facturas y pagos, se lee de campos cuyos nombres hemos tenido que inferir. Esto muestra una fila real de cada endpoint de su propia cuenta, para adaptar el módulo a lo que su cuenta envía realmente.';
$_MODULE['<{PrestashopAPI}prestashop>8c97b6869b7a8ca6c4d6ec89ea13cbe0'] = 'Son datos en vivo de su cuenta de vendedor y pueden contener nombres o correos de compradores. Elimine cualquier dato personal antes de compartirlos.';
